const Web3 = require('web3');
const WebSocket = require('ws');
const { ethers } = require('ethers');

class MEVBot {
  constructor(providerUrl, privateKey, gasPriceMultiplier = 1.5) {
    this.web3 = new Web3(providerUrl);
    this.provider = new ethers.providers.JsonRpcProvider(providerUrl);
    this.wallet = new ethers.Wallet(privateKey, this.provider);
    this.gasPriceMultiplier = gasPriceMultiplier;
    this.pendingTxs = new Set();
    this.isMonitoring = false;
  }

  async startMonitoring() {
    this.isMonitoring = true;
    const ws = new WebSocket(this.web3.currentProvider.connection.url);
    
    ws.on('open', () => {
      console.log('Connected to Ethereum node');
    });

    ws.on('message', async (data) => {
      try {
        const message = JSON.parse(data);
        if (message.method === 'eth_pendingTransactions') {
          await this.processPendingTransactions(message.params[0]);
        }
      } catch (error) {
        console.error('Error processing message:', error);
      }
    });

    ws.on('error', (error) => {
      console.error('WebSocket error:', error);
    });
  }

  async processPendingTransactions(transactions) {
    for (const tx of transactions) {
      if (this.pendingTxs.has(tx.hash)) continue;
      
      this.pendingTxs.add(tx.hash);
      
      try {
        const txData = await this.analyzeTransaction(tx);
        if (txData.isArbitrage) {
          await this.executeArbitrage(txData);
        }
      } catch (error) {
        console.error('Error analyzing transaction:', error);
      }
    }
  }

  async analyzeTransaction(tx) {
    try {
      const txReceipt = await this.web3.eth.getTransactionReceipt(tx.hash);
      if (txReceipt) return null;

      const txDetails = await this.web3.eth.getTransaction(tx.hash);
      const gasPrice = parseInt(txDetails.gasPrice);
      
      // Simple arbitrage detection logic
      const isArbitrage = this.detectArbitrageOpportunity(txDetails);
      
      return {
        hash: tx.hash,
        from: tx.from,
        to: tx.to,
        gasPrice: gasPrice,
        isArbitrage: isArbitrage,
        timestamp: Date.now()
      };
    } catch (error) {
      return null;
    }
  }

  detectArbitrageOpportunity(tx) {
    // Basic arbitrage detection - this would be more sophisticated in production
    const toAddress = tx.to?.toLowerCase();
    const fromAddress = tx.from?.toLowerCase();
    
    // Check for known arbitrage patterns
    const arbitragePatterns = [
      '0x7a250d5630b4cf539739df2c5dacb4c659f2488d', // Uniswap V2 Router
      '0x1094125858731210577821131500752057427100', // Other DEX router
    ];
    
    return arbitragePatterns.some(pattern => 
      toAddress?.includes(pattern) || 
      (tx.input && tx.input.length > 2)
    );
  }

  async executeArbitrage(txData) {
    try {
      const gasPrice = Math.floor(txData.gasPrice * this.gasPriceMultiplier);
      
      // Get current nonce
      const nonce = await this.wallet.getTransactionCount();
      
      // Create transaction with higher gas price
      const tx = {
        to: txData.to,
        gasPrice: gasPrice,
        nonce: nonce,
        gasLimit: 200000,
        value: txData.value || 0,
        data: txData.input || '0x'
      };

      // Sign and send transaction
      const signedTx = await this.wallet.signTransaction(tx);
      const result = await this.provider.sendTransaction(signedTx);
      
      console.log(`Front-run transaction submitted: ${result.hash}`);
      
      // Remove from pending set
      this.pendingTxs.delete(txData.hash);
      
      return result;
    } catch (error) {
      console.error('Error executing arbitrage:', error);
      this.pendingTxs.delete(txData.hash);
      return null;
    }
  }

  async getGasPrice() {
    try {
      const gasPrice = await this.web3.eth.getGasPrice();
      return parseInt(gasPrice);
    } catch (error) {
      return 20000000000; // Default gas price
    }
  }

  stopMonitoring() {
    this.isMonitoring = false;
    console.log('Monitoring stopped');
  }
}

